import{_ as e,a as r,b as t}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as d,o as l,c as o,a2 as i}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Añadir un canal Cloudflare R2","description":"","frontmatter":{},"headers":[],"relativePath":"es/upload/cloudflare-r2.md","filePath":"es/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),c={name:"es/upload/cloudflare-r2.md"};function n(u,a,s,p,b,h){return l(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="anadir-un-canal-cloudflare-r2" tabindex="-1">Añadir un canal Cloudflare R2 <a class="header-anchor" href="#anadir-un-canal-cloudflare-r2" aria-label="Permalink to &quot;Añadir un canal Cloudflare R2&quot;">​</a></h1><p>El canal Cloudflare R2 guarda archivos en un bucket de R2.</p><h2 id="cuando-conviene" tabindex="-1">Cuándo conviene <a class="header-anchor" href="#cuando-conviene" aria-label="Permalink to &quot;Cuándo conviene&quot;">​</a></h2><ul><li>Quieres gestionar almacenamiento dentro del ecosistema Cloudflare.</li><li>Vas a usar R2 como destino principal de ImgBed.</li><li>Quieres combinar R2 con un dominio personalizado o CDN.</li></ul><h2 id="que-preparar" tabindex="-1">Qué preparar <a class="header-anchor" href="#que-preparar" aria-label="Permalink to &quot;Qué preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Uso</th></tr></thead><tbody><tr><td>Cuenta de Cloudflare</td><td>Gestionar R2 y tokens</td></tr><tr><td>Bucket R2</td><td>Destino real de los archivos</td></tr><tr><td>Account ID</td><td>Identificar la cuenta</td></tr><tr><td>API Token</td><td>Permitir lectura y escritura en R2</td></tr><tr><td>Dominio personalizado</td><td>Opcional, para URLs públicas más limpias</td></tr></tbody></table><h2 id="crear-el-bucket" tabindex="-1">Crear el bucket <a class="header-anchor" href="#crear-el-bucket" aria-label="Permalink to &quot;Crear el bucket&quot;">​</a></h2><p>En Cloudflare Dashboard, abre <code>R2 Object Storage</code> y crea un bucket nuevo.</p><p><img src="'+e+'" alt="Crear bucket R2" loading="lazy"></p><p>Guarda el nombre exacto del bucket, porque debes introducirlo igual en ImgBed.</p><h2 id="buscar-el-account-id" tabindex="-1">Buscar el Account ID <a class="header-anchor" href="#buscar-el-account-id" aria-label="Permalink to &quot;Buscar el Account ID&quot;">​</a></h2><p>En la página de la cuenta de Cloudflare puedes ver el Account ID.</p><p><img src="'+r+'" alt="Account ID" loading="lazy"></p><h2 id="rellenar-en-imgbed" tabindex="-1">Rellenar en ImgBed <a class="header-anchor" href="#rellenar-en-imgbed" aria-label="Permalink to &quot;Rellenar en ImgBed&quot;">​</a></h2><p>En Configuración de subida, abre <code>Añadir canal</code> y elige <code>Cloudflare R2</code>.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nombre del canal</td><td>Nombre fácil de reconocer</td></tr><tr><td>Account ID</td><td>Account ID de Cloudflare</td></tr><tr><td>Bucket</td><td>Nombre del bucket R2</td></tr><tr><td>API Token</td><td>Token con permiso sobre R2</td></tr><tr><td>Dominio personalizado</td><td>Opcional</td></tr><tr><td>Directorio</td><td>Opcional; normalmente <code>imgbed</code></td></tr></tbody></table><h2 id="limite-de-capacidad" tabindex="-1">Límite de capacidad <a class="header-anchor" href="#limite-de-capacidad" aria-label="Permalink to &quot;Límite de capacidad&quot;">​</a></h2><p>Puedes activar límite de capacidad si quieres controlar cuándo deja de usarse este canal.</p><p><img src="'+t+'" alt="Límite de capacidad" loading="lazy"></p><p>Cuando el uso llega al umbral configurado, ImgBed puede dejar de seleccionar ese canal para nuevas subidas.</p><h2 id="verificacion" tabindex="-1">Verificación <a class="header-anchor" href="#verificacion" aria-label="Permalink to &quot;Verificación&quot;">​</a></h2><ol><li>La tarjeta del canal R2 aparece tras guardar.</li><li>El canal está habilitado.</li><li>Sube una imagen de prueba.</li><li>Comprueba que el objeto aparece en el bucket.</li><li>Abre el enlace devuelto por ImgBed.</li></ol><h2 id="errores-habituales" tabindex="-1">Errores habituales <a class="header-anchor" href="#errores-habituales" aria-label="Permalink to &quot;Errores habituales&quot;">​</a></h2><ul><li>Account ID o nombre de bucket incorrecto.</li><li>Token sin permisos suficientes sobre el bucket.</li><li>Dominio personalizado no conectado al bucket.</li><li>El canal quedó fuera por límite de capacidad.</li></ul>',24)])])}const _=d(c,[["render",n]]);export{k as __pageData,_ as default};
